INSERT INTO `datosadjuntos` VALUES(133,'documento','application/pdf','Documento_Web','Poda y entutorado del tomate','Este documento del Ministerio de Agricultura de España detalla las prácticas culturales esenciales para el cultivo intensivo de tomate, tanto en invernadero como al aire libre. Aporta metodologías específicas para la poda de formación, el despunte, el deshojado y el entutorado. Explica que la poda limita el número de tallos, lo que resulta en frutos de mayor calidad (tamaño, uniformidad de color, tersura) y mayor precocidad. También facilita las labores de cultivo, el control de plagas y enfermedades, y la recolección. Se describen métodos de poda como dejar uno o dos tallos principales y eliminar los brotes axilares, así como técnicas específicas como la "poda Curro" y la "poda en candelabro". Además, aborda los sistemas de entutorado con cuerdas o alambres en invernaderos y el tradicional "caballete", señalando sus ventajas y desventajas.',NULL,NULL,NULL,'https://web.archive.org/web/2/https://vertexaisearch.cloud.google.com/grounding-api-redirect/AUZIYQHgMh-cMAXxM4eK7A2-YSowLyz22hiyx38RfLVPn920uJEtypnsozsxt0ksF6RpeuGdr5vRCKlHeHiIWNRZgcJtC1PZDsiz8No8geOS9UNBiMCLbs5kqce3GrelWLnwMtC6p2daXpx5zMllHBDVu3qlSIcnPsflDJIiFXE6ZKn5DM0t',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-26 17:02:57','2026-04-26 17:10:40','2026-04-26 17:10:40',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(134,'documento','application/pdf','Documento_Web','Poda y entutorado del tomate','Este documento, parte de las "Hojas Divulgadoras del Ministerio de Agricultura" de España, se centra en las técnicas de poda y entutorado necesarias para el cultivo intensivo de tomate, tanto en invernadero como al aire libre. Describe el "destallado" o "desbrote" como una operación fundamental para limitar el número de tallos, lo que resulta en una mayor precocidad, frutos de mayor tamaño, mejor uniformidad de color, mayor tersura y limpieza, facilidad en las prácticas de cultivo, mejor control de plagas y enfermedades, y mayor rapidez en la recolección. El manual detalla diferentes formas de poda, incluyendo la eliminación de brotes axilares dejando uno o dos tallos principales, y la poda del "curro". También aborda los factores que influyen en el número de brazos a dejar (marco de plantación, precocidad deseada, mano de obra, variedad y clima) y presenta diversos sistemas de entutorado.','',NULL,NULL,'https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1973_1974_19.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-26 17:39:04','2026-04-26 17:39:23','2026-04-26 17:39:23',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(135,'documento','application/pdf','Documento_Web','Poda y entutorado del tomate','Este documento, parte de las "Hojas Divulgadoras del Ministerio de Agricultura" de España, se centra en las técnicas de poda y entutorado necesarias para el cultivo intensivo de tomate, tanto en invernadero como al aire libre. Describe el "destallado" o "desbrote" como una operación fundamental para limitar el número de tallos, lo que resulta en una mayor precocidad, frutos de mayor tamaño, mejor uniformidad de color, mayor tersura y limpieza, facilidad en las prácticas de cultivo, mejor control de plagas y enfermedades, y mayor rapidez en la recolección. El manual detalla diferentes formas de poda, incluyendo la eliminación de brotes axilares dejando uno o dos tallos principales, y la poda del "curro". También aborda los factores que influyen en el número de brazos a dejar (marco de plantación, precocidad deseada, mano de obra, variedad y clima) y presenta diversos sistemas de entutorado.','',NULL,NULL,'https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1973_1974_19.pdf',0,NULL,NULL,NULL,NULL,0,2,NULL,0,'2026-04-26 17:39:04','2026-04-26 17:39:21','2026-04-26 17:39:21',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(136,'documento','application/pdf','Documento_Web','mapa.gob.es','Este documento de la Extensión Cooperativa de Alabama (Alabama Cooperative Extension System) proporciona técnicas de poda para la producción de tomates frescos, con el objetivo de lograr plantas más saludables y frutos de mayor tamaño. Explica que la poda ayuda a mantener un equilibrio entre el crecimiento vegetativo y reproductivo, evitando el crecimiento excesivo del follaje que podría reducir el tamaño del fruto. Recomienda la poda moderada para obtener vides más pequeñas y frutos más grandes que maduran antes, además de mantener las plantas y frutos alejados del suelo para controlar enfermedades. El método más común descrito es la poda a dos tallos, eliminando los brotes laterales (chupones) que aparecen en las axilas de cada hoja, especialmente los que se encuentran inmediatamente debajo del primer racimo floral. Se aconseja eliminar los chupones cuando son pequeños (no más de 2 a 4 pulgadas de longitud) para evitar el desperdicio de energía de la planta y reducir los puntos de entrada para patógenos. También se recomienda podar temprano en la mañana, después de que las plantas se hayan secado.','',NULL,NULL,'https://web.archive.org/web/2/https://vertexaisearch.cloud.google.com/grounding-api-redirect/AUZIYQGIZRjB6p-RMJQSIrqZRmkmIzA_Qp1uvI_VqZQx5doWEB_T-AWTxIKa5IbDrDM4F8dyRUvovFiXRLOljznwiR1uOezIkz6_-cLDBhc8bXLy4WzfdNcwEGF6HC6z9tfSXomjXKKHFUForVYWiUJnUwWcyLv1iNRrStHcksZhSMZGDQg=',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-26 17:44:00','2026-04-26 17:45:50','2026-04-26 17:45:50',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(137,'documento','application/pdf','Documento_Web','mapa.gob.es','Informe técnico del INTA (Argentina) que aborda las prácticas culturales esenciales de conducción y poda en el cultivo de tomate, destacando su importancia para la rentabilidad, la calidad del fruto y el control de plagas y enfermedades en sistemas intensivos.','- **Contexto:** El cultivo intensivo de tomate (en invernadero o al aire libre) requiere prácticas culturales específicas para obtener una buena producción y rentabilidad.\n- **Prácticas imprescindibles:** Poda o destallado, despunte o pinzamiento de los tallos, deshojado o limpieza de hojas, y entutorado o enrame.\n- **Poda o destallado:**\n  - **Objetivo:** Encauzar el desarrollo de la vegetación, limitar el número de tallos y, por tanto, la cantidad de fruto por planta, a cambio de una mayor precocidad.\n  - **Ventajas:** Mayor calidad de los frutos (mayor tamaño, uniformidad de color, más tersos y limpios), mayor facilidad en las prácticas de cultivo, mejor control de plagas y enfermedades, mayor rapidez y comodidad en la recolección, y aumento de la producción por unidad de superficie (al cultivar más plantas).\n  - **Inconvenientes:** Excesiva mano de obra.\n  - **Método:** Consiste en dejar varios tallos guía y cortar todos los brotes que salen en las axilas de las hojas de esos tallos.\n- **Formas de poda:**\n  - **Poda normal (más usada):** Se deja el tallo principal y uno o dos hijos que brotan en las axilas de las hojas de ese tallo; se desbrotan todos los hijuelos que salen en los dos o tres brazos que se dejan.\n  - **Poda "Curro":** Se dejan uno o dos tallos que se deshijan a medida que la planta crece, y se deja otro tallo denominado "curro" al cual se le despuntan o cortan la yema terminal inmediatamente después de formado el primer racimo de flores.\n  - **Poda en candelabro simple:** Se describe un esquema donde la planta queda con dos tallos principales y dos secundarios.\n- **Despunte o pinzamiento:** Se refiere a cortar la yema terminal de los tallos para detener su crecimiento y fomentar el desarrollo de frutos existentes.\n- **Deshojado:** Eliminación de hojas, especialmente las inferiores o enfermas, para mejorar la aireación y reducir la incidencia de plagas y enfermedades.',NULL,NULL,'https://web.archive.org/web/2/https://vertexaisearch.cloud.google.com/grounding-api-redirect/AUZIYQFdPOERc1H33iokpp7j3HtbCxdW-bQ9pV5_RCW4M2IP4-CiNUyGF1Ar5HN7diKs8mJUPE3vBOwtsa5UHAMvvHZ0ldfjFI1CoTgzhqWd-CQcTGvLM-2YUJMRcNBOeYa9kJ-GiLEsU5QtUDoE9KtMt55kbs5VRHSw_vII3mvUq9dSDlal',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-26 17:46:49','2026-04-26 17:48:56','2026-04-26 17:48:56',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(138,'documento','application/pdf','Documento_Web','mapa.gob.es','Este documento del Ministerio de Agricultura detalla las técnicas de poda y destallado en el cultivo intensivo de tomate, tanto en invernadero como al aire libre, buscando optimizar la producción y calidad del fruto.','Apuntes de estudiante:\n*   La poda o destallado es una práctica cultural imprescindible en el cultivo intensivo de tomate para asegurar la rentabilidad.\n*   Su objetivo principal es encauzar el desarrollo vegetativo, limitando el número de tallos para lograr mayor precocidad y una mejor calidad de los frutos (mayor tamaño, uniformidad de color, tersura y limpieza).\n*   Entre las ventajas adicionales se incluyen: mayor facilidad en las prácticas de cultivo, mejor control de plagas y enfermedades, mayor rapidez y comodidad en la recolección, y un aumento de la producción por unidad de superficie.\n*   El principal inconveniente es la considerable mano de obra que requiere esta práctica y las operaciones asociadas como el entutorado.\n*   Se describen diferentes formas de poda:\n    *   **Poda normal:** Consiste en dejar el tallo principal y uno o dos hijos que brotan de las axilas de las hojas de ese tallo, eliminando todos los demás hijuelos.\n    *   **Poda \'Curro\':** Se dejan uno o dos tallos principales y un tallo adicional denominado \'curro\', al cual se le despuntará la yema terminal inmediatamente después de la formación del primer racimo de flores.\n    *   **Poda en candelabro simple:** La planta se configura para tener dos tallos principales y dos secundarios.\n*   El destallado implica dejar varios tallos guía y cortar todos los brotes que emergen de las axilas de las hojas de esos tallos.\n*   Se autoriza la reproducción íntegra de la publicación mencionando su origen: «Hojas Divulgadoras del Ministerio de Agricultura».',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_3_138_1778428712910.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1973_19.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-26 17:49:39','2026-05-12 10:13:41','2026-05-12 10:13:41',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(139,'documento','application/pdf','Documento_Web','icta.gob.gt','Este manual del Instituto de Ciencia y Tecnología Agrícolas (ICTA) de Guatemala ofrece recomendaciones técnicas para el cultivo de tomate bajo invernadero, incluyendo pautas específicas para la frecuencia de poda según las condiciones climáticas.','Apuntes de estudiante:\n*   El manual es el resultado de la colaboración entre el Ministerio de Agricultura Ganadería y Alimentación (MAGA) de Guatemala, el ICTA y la Agencia de Cooperación Internacional del Japón (JICA).\n*   Proporciona recomendaciones técnicas para el cultivo de tomate, papa, frijol y haba bajo invernadero, con el fin de mejorar la producción de alimentos y la seguridad alimentaria de las comunidades rurales.\n*   **Frecuencia de poda del tomate según el clima:**\n    *   En condiciones frías del altiplano, se recomienda podar el tomate una vez a la semana.\n    *   En climas templados, la frecuencia de poda aumenta a dos veces por semana.\n*   Es crucial que los brotes axilares a podar tengan una longitud de 2.5 a 5 centímetros.\n*   Las variedades de tomate a las que se refieren estas recomendaciones son de hábito de crecimiento indeterminado, lo que significa que continúan su crecimiento después de la floración con una guía.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_3_139_1778428755684.jpg','https://web.archive.org/web/2/https://www.icta.gob.gt/publicaciones/Frijol/Manual%20cultivos.pdf',0,NULL,NULL,NULL,NULL,0,2,NULL,0,'2026-04-26 17:50:35','2026-05-12 10:13:39','2026-05-12 10:13:39',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(140,'documento','application/pdf','Documento_Web','fao.org','Este manual de la FAO y CORPOICA detalla las Buenas Prácticas Agrícolas para la producción de tomate en condiciones protegidas, haciendo énfasis en la poda de variedades de crecimiento indeterminado para optimizar la producción y calidad del fruto.','Apuntes de estudiante:\n*   El manual se centra en la implementación de Buenas Prácticas Agrícolas (BPA) en sistemas de producción de tomate bajo condiciones protegidas, abarcando desde la preparación del terreno hasta la cosecha y el embalaje.\n*   Para materiales de tomate de crecimiento indeterminado, la poda es una práctica fundamental que se realiza en diversas partes de la planta, incluyendo tallos, chupones, hojas, flores y frutos.\n*   **Los objetivos de la poda son:**\n    *   Crear mejores condiciones para las partes de la planta que están directamente relacionadas con la producción.\n    *   Eliminar aquellas partes que no contribuyen a la cosecha y que, por el contrario, consumen energía que podría destinarse al desarrollo de frutos.\n    *   Contribuir a la obtención de frutos de mayor tamaño y calidad.\n*   La implementación de estas BPA contribuye al desarrollo de políticas de producción más limpia y al desarrollo rural.\n*   Este documento es una colaboración entre la Organización de las Naciones Unidas para la Alimentación y la Agricultura (FAO), la Gobernación de Antioquia, MANA y la Corporación Colombiana de Investigación Agropecuaria (CORPOICA).',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_3_140_1778428778395.jpg','https://web.archive.org/web/2/https://www.fao.org/4/a1374s/a1374s00.pdf',0,NULL,NULL,NULL,NULL,0,3,NULL,0,'2026-04-26 17:51:10','2026-05-12 10:13:28','2026-05-12 10:13:28',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(141,'documento','application/pdf','Documento_Web','platicar.go.cr','Esta guía técnica del Instituto Nacional de Innovación y Transferencia en Tecnología Agropecuaria (INTA) de Costa Rica aborda el cultivo de tomate, incluyendo la poda de follaje o saneamiento y la poda apical, destacando su importancia para el desarrollo óptimo y la calidad de los racimos.','Apuntes de estudiante:\n*   La guía técnica es elaborada por el Instituto Nacional de Innovación y Transferencia en Tecnología Agropecuaria (INTA) de Costa Rica.\n*   Se describen dos tipos principales de poda:\n    *   **Poda de follaje o saneamiento:** Consiste en la eliminación de hojas dañadas, viejas o enfermas para mantener la sanidad general de la planta y mejorar la aireación.\n    *   **Poda apical:** Implica la poda del eje principal en híbridos y/o variedades de tomate de crecimiento indeterminado.\n*   La poda apical es una práctica que propicia la precocidad del cultivo y favorece un mayor tamaño en los racimos que se encuentran en desarrollo.\n*   Es de suma importancia retirar los restos de poda del campo de cultivo para prevenir la diseminación de posibles enfermedades.\n*   En general, la poda es una práctica común en variedades de crecimiento indeterminado, donde se seleccionan dos o tres tallos principales y se podan los demás.\n*   Se recomienda encarecidamente desinfectar los instrumentos utilizados para la poda como medida preventiva contra la propagación de enfermedades.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_3_141_1778428751796.jpg','https://web.archive.org/web/2/http://platicar.go.cr/images/buscador/documents/pdf/2021/Tomate_Edit.pdf',0,NULL,NULL,NULL,NULL,0,4,NULL,0,'2026-04-26 17:51:24','2026-05-12 10:13:25','2026-05-12 10:13:25',NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
