INSERT INTO `datosadjuntos` VALUES(157,'documento','application/pdf','Documento_Web','scribd.com','Documento técnico del Dr. Francisco Camacho Ferre del Departamento de Producción Vegetal de la Universidad de Almería sobre el cultivo del calabacín bajo invernadero, abordando la morfología, fisiología y exigencias ambientales, incluyendo la producción de plántulas.','Apuntes sobre el semillero de calabacín en invernadero:\n*   **Morfología de la plántula**: Se menciona la \'Plántula desarrollada en bandeja de semillero\' como parte de la morfología de los órganos vegetativos y productivos del calabacín.\n*   **Germinación**: El documento cubre la germinación como un proceso fisiológico clave en el desarrollo de la planta.\n*   **Ciclo de producción**: El calabacín entra en producción en un periodo de 35 a 55 días desde la siembra.\n*   **Exigencias climáticas**: El calabacín es menos exigente en altas temperaturas que otras cucurbitáceas como el melón o el pepino, pero es sensible a los fríos y las heladas. La temperatura óptima de germinación se sitúa entre 20-25°C.\n*   **Humedad óptima**: La humedad relativa óptima para el cultivo del calabacín en invernadero oscila entre el 65% y el 80%.',NULL,NULL,'https://web.archive.org/web/2/https://es.scribd.com/document/358661619/Ficha-Tecnica-Calabacin',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-29 10:48:43','2026-04-29 10:56:48','2026-04-29 10:56:48',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(158,'documento','application/pdf','Documento_Web','uky.edu','Manual sobre el cultivo intensivo del calabacín que aborda aspectos botánicos, exigencias climáticas, abonado y, de manera relevante, las enfermedades producidas por hongos como el oídio y la roña (Cladosporium cucumerinum).','-   **Generalidades del cultivo:** El calabacín (*Cucurbita pepo*) es una planta anual de vegetación compacta y crecimiento indeterminado, cultivada en ciclos cortos (otoño o primavera).\n-   **Exigencias climáticas:** Prefiere climas templados o cálidos, sensible a fríos y heladas. Temperatura óptima para floración entre 20°C (noche) y 25°C (día). Humedad óptima en invernadero entre 65% y 80%.\n-   **Suelo:** Profundo, fresco, bien drenado y rico en materia orgánica.\n-   **Enfermedades fúngicas:**\n    -   **Oídio:** Muy extendida y de fácil diagnóstico. Afecta a toda la planta, especialmente hojas (haz y envés). Causada por *Erysiphe cichoracearum* y *Sphaerotheca fuliginia*. Produce manchas aisladas y circulares con micelio blanco pulverulento.\n    -   **Roña (Sarna):** Causada por el hongo *Cladosporium cucumerinum*. Se refugia en restos de plantas enfermas y se propaga por semillas y restos vegetales.\n    -   **Síntomas de Roña en frutos:** Manchas deprimidas con exudación que se recubre con una masa de esporas.\n-   **Manejo de enfermedades:** La prevención es clave. Rotación de cultivos, fertilización adecuada, eliminación de plantas viejas y hojas enfermas. Evitar el exceso de humedad favorece la aparición de enfermedades fúngicas.\n-   **Otras enfermedades mencionadas en el contexto de cucurbitáceas (no específicas de este documento para calabacín pero relevantes):** Pudrición radicular (*Phoma, Fusarium, Sclerotinia*), mildiu velloso (*Pseudoperonospora cubensis*), botrytis (*Botrytis cinerea*), virus del mosaico amarillo del calabacín, virus del mosaico del pepino, mancha bacteriana de la hoja (*Xanthomonas campestris*).',NULL,NULL,'https://web.archive.org/web/2/https://plantpathology.mgcafe.uky.edu/sites/plantpathology.ca.uky.edu/files/PPFS-VG-10-S.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-29 10:57:40','2026-04-29 10:59:30','2026-04-29 10:59:30',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
