INSERT INTO `datosadjuntos` VALUES(164,'documento','application/pdf','Documento_Web','Poda de Hortalizas en Invernaderos','Documento técnico del Ministerio de Agricultura, Pesca y Alimentación de España que aborda la poda en cultivos hortícolas intensivos en invernadero, incluyendo el calabacín.','- La poda en cultivos hortícolas intensivos en invernadero busca encauzar el crecimiento para una mayor rentabilidad, especialmente en marcos de plantación estrechos.\n- El objetivo general es dejar uno o varios tallos, eliminando brotes, hojas, frutos y chupones que no fructifican o tienen un desarrollo excesivo.\n- Se puede utilizar un código de 3 cifras para indicar el tipo de poda (ej. 2-8-2 para número de brazos, hojas por encima de ramos de 2º orden y hojas por encima de tallos de 3º orden).\n- La poda debe ser racional y con un criterio económico, adaptándose a la especie, marco de plantación, forma de vegetar, fructificar y climatología.',NULL,NULL,'https://web.archive.org/web/2/https://es.scribd.com/document/135961428/calabacin-cladosporium',0,NULL,NULL,NULL,NULL,0,2,NULL,0,'2026-04-29 12:30:07','2026-04-29 13:14:32','2026-04-29 13:14:32',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
