INSERT INTO `datosadjuntos` VALUES(166,'documento','application/pdf','Documento_Web','Poda de Hortalizas en Invernadero (Calabacín)','Guía del Ministerio de Agricultura sobre técnicas de poda para hortalizas en invernadero, con sección específica para calabacín.','Detalla poda de flores, frutos y hojas envejecidas o dañadas. Menciona aclareo de frutos para mejorar calidad y poda de yemas/brotes terminales (pinzamiento/despunte) para favorecer órganos de producción. También aborda el destallado.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_166_1777473117207.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1995_01-02.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-29 14:31:36','2026-04-29 14:35:31','2026-04-29 14:35:31',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(167,'documento','application/pdf','Documento_Web','Poda de Hortalizas en Invernadero (Calabacín)','Este documento del Ministerio de Agricultura, Pesca y Alimentación detalla las técnicas de poda aplicadas a hortalizas en invernadero, con un enfoque específico en el calabacín. Aborda la poda de formación, sugiriendo la poda a dos brazos para fomentar el desarrollo de guías secundarias, y la poda de brotes, recomendando la eliminación de brotes secundarios que surgen por exceso de abonado nitrogenado. También cubre la poda de hojas para mejorar la aireación y reducir enfermedades, y el aclareo de frutos para optimizar la calidad y el tamaño de los restantes, eliminando los dañados o deformes.','- No se acostumbra poda de formación, pero se puede ensayar la poda a dos brazos cortando el tallo principal tras dos hojas verdaderas.\n- Eliminar brotes secundarios que aparecen por exceso de abonado nitrogenado para evitar frutos no comerciales.\n- Realizar poda de hojas (deshojado) para mejorar la aireación, reducir enfermedades y facilitar labores, evitando cortar hojas superiores que protegen los frutos.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_167_1777473376143.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1995_01-02.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-29 14:36:02','2026-04-29 14:39:52','2026-04-29 14:39:52',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(168,'documento','application/pdf','Documento_Web','Poda de Hortalizas en Invernadero: Calabacín','Este documento del Ministerio de Agricultura, Pesca y Alimentación aborda la poda en cultivos hortícolas intensivos bajo invernadero, con un enfoque específico en el calabacín. Detalla cómo la poda es fundamental para regular el crecimiento y la productividad, mejorando la aireación de la planta y facilitando las labores culturales. Se enfatiza la eliminación de hojas envejecidas o dañadas para reducir la incidencia de enfermedades criptogámicas y plagas, aunque se advierte sobre el aumento de mano de obra y el riesgo de botrytis en los cortes. Se describen métodos para el aclareo de frutos y la poda de yemas y brotes terminales para optimizar la calidad y el número de frutos.','La poda en calabacín elimina flores, frutos, hojas y brotaciones secundarias para mejorar la aireación y reducir enfermedades criptogámicas.\nSe facilitan las prácticas culturales al eliminar masa foliar y se reducen focos de plagas al suprimir hojas dañadas o enfermas.\nInconvenientes de la poda incluyen un mayor aporte de mano de obra y la posibilidad de ataque de botrytis sobre los cortes efectuados.\nEl deshojado se realiza dando cortes limpios en la unión del peciolo con el tallo, siempre por debajo de los frutos más bajos, evitando podar las hojas superiores para no desproteger los frutos del sol.\nSe puede practicar una poda intermedia para regularizar la producción y desarrollo, pinzando brotes laterales a 1 fruto entre 0.60-1.5 m de altura, y despuntando tallos laterales a 2 frutos a partir de 1.5 m.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_168_1777473666939.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1995_01-02.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-29 14:40:48','2026-04-30 13:49:03','2026-04-30 13:49:03',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(169,'documento','application/pdf','Documento_Web','Poda de Hortalizas en Invernadero (Calabacín)','Este documento del Ministerio de Agricultura, Pesca y Alimentación, se centra en las técnicas de poda aplicadas a cultivos hortícolas intensivos bajo invernadero, con una sección dedicada al calabacín. Detalla la importancia de eliminar hojas envejecidas o con desarrollo excesivo para optimizar la luminosidad y la circulación del aire dentro de la planta, lo cual es crucial para la prevención de enfermedades fúngicas. Además, aborda la supresión de brotes secundarios y el aclareo de frutos, prácticas esenciales para mejorar la calidad y el rendimiento de la cosecha, siempre enfatizando la necesidad de realizar cortes limpios para minimizar el riesgo de infecciones.','La poda en calabacín implica la eliminación de flores, frutos, hojas y brotaciones secundarias, especialmente en variedades que muestran un desarrollo excesivo.\nUno de los objetivos principales es mejorar la aireación de la planta, lo que disminuye significativamente las condiciones favorables para el ataque de enfermedades criptogámicas como el oídio.\nLa supresión de hojas dañadas o enfermas es fundamental para reducir los focos de penetración y desarrollo de plagas y enfermedades aéreas, contribuyendo a la sanidad general del cultivo.\nComo inconvenientes de la poda, se mencionan el mayor aporte de mano de obra y la posibilidad de ataques de Botrytis sobre los cortes realizados, lo que requiere precauciones post-poda.\nEl deshojado se justifica cuando las hojas de la parte baja de la planta están muy envejecidas o su excesivo desarrollo dificulta la luminosidad y aireación, debiendo realizarse cortes limpios en la unión del peciolo con el tallo, siempre por debajo de los frutos más bajos.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_169_1777557022647.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1995_01-02.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-30 13:50:04','2026-04-30 13:56:29','2026-04-30 13:56:29',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(170,'documento','application/pdf','Documento_Web','Poda de Hortalizas en Invernadero: Calabacín','Este manual del Ministerio de Agricultura, Pesca y Alimentación detalla las técnicas de poda aplicables al calabacín en cultivos de invernadero. Se enfoca en la eliminación de brotes secundarios no comerciales, el deshojado de hojas envejecidas o dañadas para mejorar la aireación y luminosidad, y la supresión de frutos enfermos o deformados. La poda busca optimizar la producción y la sanidad de la planta, reduciendo la incidencia de enfermedades criptogámicas y facilitando las labores culturales, aunque advierte sobre la posible reducción de la producción si se excede en el corte.','La poda en calabacín elimina flores, frutos y hojas, así como brotaciones secundarias que pueden surgir por un desarrollo excesivo o en variedades específicas.\nEl deshojado se justifica en hojas muy envejecidas o cuando su excesivo desarrollo dificulta la luminosidad y aireación interna de la planta.\nLos cortes para el deshojado deben ser limpios, realizados en la unión del peciolo con el tallo, siempre por debajo de los frutos más bajos, preferentemente por la mañana y con ambiente seco.\nNo se deben eliminar las hojas superiores, ya que esto puede exponer los frutos al sol, causando daños y endurecimiento.\nTras una poda intensa de hojas, se recomienda aplicar un tratamiento fungicida (anti-botrytis) para prevenir infecciones en los cortes.\nLa supresión de brotes secundarios es crucial en variedades híbridas que, con un abonado nitrogenado excesivo, pueden producir frutos no comerciales.\nSe deben suprimir los frutos dañados por plagas o enfermedades, deformados o excesivamente desarrollados que no sean comerciales.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_170_1777557437454.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1995_01-02.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-30 13:57:02','2026-04-30 13:57:29','2026-04-30 13:57:29',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(171,'documento','application/pdf','Documento_Web','Poda de Formación y Brotes en Calabacín','Este estudio de la Universidad de Zaragoza, aunque enfocado en la evaluación agronómica de variedades de calabacín, incluye una sección relevante sobre la poda. Destaca que, si bien la poda de formación no es una práctica común, se considera interesante la poda a dos brazos, que implica cortar el tallo principal por encima de las dos primeras hojas verdaderas para fomentar el crecimiento de dos brazos secundarios y potencialmente aumentar la producción. También aborda la poda de brotes laterales que pueden surgir en variedades híbridas debido a un exceso de nitrógeno, y el deshojado de la parte inferior de la planta.','La poda de formación en calabacín no es habitual, pero se sugiere la poda a dos brazos cortando el tallo principal tras las dos primeras hojas verdaderas para estimular dos brazos secundarios.\nEsta técnica de poda a dos brazos podría influir en una mayor producción de frutos.\nLas variedades híbridas de calabacín pueden desarrollar brotes secundarios con un exceso de abonado nitrogenado, los cuales deben ser eliminados.\nEl deshojado se realiza en las hojas inferiores, envejecidas o dañadas, para mejorar la aireación y la penetración de la luz.\nLos cortes de deshojado deben ser limpios y realizados en la unión del peciolo con el tallo, siempre por debajo de los frutos más bajos.\nSe recomienda realizar el deshojado por la mañana y en condiciones de ambiente seco para minimizar el riesgo de enfermedades.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_171_1777557474636.jpg','https://web.archive.org/web/2/https://zaguan.unizar.es/record/76356/files/TAZ-TFG-2018-4730.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-04-30 13:57:33','2026-05-01 12:46:42','2026-05-01 12:46:42',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(172,'documento','application/pdf','Documento_Web','Cultivo de Calabacín en Invernadero: Riego y Fertilización','Este documento de la Universidad de Almería detalla el cultivo de calabacín bajo invernadero, con un enfoque particular en el manejo del riego y la fertilización. Se describen las necesidades hídricas y nutricionales de la planta, así como las pautas para la aplicación de fertilizantes en diferentes etapas del cultivo, tanto en riego a manta como en fertirrigación hidropónica. Se enfatiza la importancia de ajustar el pH de la solución de riego y se proporcionan unidades fertilizantes recomendadas por hectárea para lograr producciones óptimas.','Para una producción media de 70.000-80.000 kg/ha comercializable en riego a manta y terreno enarenado, se recomiendan 300-400 kg de Nitrógeno (N), 150-200 kg de Fósforo (P2O5) y 350-500 kg de Potasio (K2O) por hectárea.\nEl primer riego se realiza antes de la siembra, incorporando abonado de fondo con sulfato amónico (350-475 kg/ha), superfosfato de cal (600-900 kg/ha) y sulfato de potasa (250-350 kg/ha).\nEl segundo riego se aplica aproximadamente a los 15-25 días de la nascencia, con 250 kg/ha de Sulfato amónico 21%, 300 kg/ha de Superfosfato de cal 18% y 150 kg/ha de Sulfato de potasa.\nEn fertirrigación hidropónica, se aconsejan 200-300 U.F. de N, 150-200 U.F. de P2O5, 350-500 U.F. de K2O y 50 U.F. de MgO por hectárea.\nEs crucial ajustar el pH de la solución de riego utilizando ácido fosfórico o nítrico según proceda.',NULL,'/api/media?path=uploads%2Fespecies_pdfs_covers%2Fcover_10_172_1777557832101.jpg','https://web.archive.org/web/2/https://cooperativas-agro.s3.eu-west-1.amazonaws.com/old/docs/02428.pdf',0,NULL,NULL,NULL,NULL,0,2,NULL,0,'2026-04-30 14:03:31','2026-05-01 12:46:44','2026-05-01 12:46:44',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
