INSERT INTO `datosadjuntos` VALUES(178,'imagen_blog','image/webp','cosecha-de-calabacines-frutos-frescos-y-listos-1777561267060.webp','Cosecha de calabacines: Frutos frescos y listos','{"seo_alt":"Calabacines recién cosechados con rocío matutino, presentados en una caja de madera rústica en el huerto.","seo_title":"Cosecha de calabacines: Frutos frescos y listos","profile_object_x":50,"profile_object_y":50,"profile_object_zoom":100,"profile_style":"","es_portada_blog":false}',NULL,NULL,NULL,'uploads/blog/cosecha-de-calabacines-frutos-frescos-y-listos-1777561267060.webp',162614,NULL,NULL,NULL,NULL,0,3,NULL,1,'2026-04-30 15:01:07',NULL,NULL,NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(179,'documento','application/pdf','Documento_Web','Evaluación Agronómica y Poda de Calabacín','Este documento técnico de la Universidad de Zaragoza aborda la evaluación agronómica de variedades de calabacín, incluyendo aspectos cruciales de la poda. Se detalla la eliminación de brotes secundarios para evitar frutos no comerciales y la poda de hojas envejecidas o excesivamente desarrolladas que dificulten la luminosidad y aireación. Se enfatiza la importancia de realizar cortes limpios en la unión del peciolo con el tallo, preferentemente por la mañana y con ambiente seco, para minimizar riesgos de enfermedades.','Las variedades híbridas de calabacín suelen emitir una sola guía, pero un exceso de abono nitrogenado puede inducir brotes secundarios que deben eliminarse.\nLa poda de brotes secundarios es crucial para mantener la calidad y comercialidad de los frutos, ya que los brotes laterales pueden producir frutos de menor valor.\nEl corte de hojas se justifica en casos de envejecimiento avanzado o desarrollo excesivo que comprometa la luminosidad y aireación interna de la planta, lo que puede disminuir la producción.\nEl deshojado debe realizarse por la mañana, con ambiente seco, efectuando cortes limpios en la unión del peciolo con el tallo, siempre por debajo de los frutos más bajos.\nEs fundamental no podar las hojas superiores que protegen los frutos del sol, y tras la poda, se recomienda aplicar tratamientos fungicidas para prevenir infecciones.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_10_179_1777639663690.jpg','https://web.archive.org/web/2/https://zaguan.unizar.es/record/76356/files/TAZ-TFG-2018-4730.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-05-01 12:47:26','2026-05-01 12:51:35','2026-05-01 12:51:35',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(180,'documento','application/pdf','HC_49232588F (1).pdf','Informe Aptitud Conducción','Este documento es un informe de reconocimiento médico y psicofísico completo para evaluar la aptitud de un individuo, detallando su historial de salud, exploraciones físicas, oftalmológicas y psicológicas, y un dictamen final.','El documento proporcionado es un informe de reconocimiento médico y psicofísico exhaustivo, no un análisis sobre una especie agrícola. Como experto agrónomo, debo señalar que el contenido es ajeno a mi campo de especialización. El informe evalúa la aptitud de un individuo, probablemente para la conducción, y se estructura en las siguientes secciones clave:\n\n*   **Anamnesis General y Datos Personales (AMG, DP, AS):** Recoge el historial médico del interesado, incluyendo preguntas sobre enfermedades, mareos, problemas cardíacos, respiratorios, y uso de alcohol o estupefacientes. Se registran datos personales como edad (18 años), sexo (V), nacionalidad (ESPAÑA), y detalles de conducción (Num de Expediente 176/2026, Tipo Permiso B). El individuo declara no padecer enfermedades ni tomar medicación habitual.\n*   **Exploración Médica General (EMG, Inspección General):** Incluye audiometría (valores de 10-20 dB en OD y OI), talla (178 cm) y peso (77 kg). La tensión arterial es 123/67 mmHg con ritmo regular. El dictamen parcial general es \'APTO\'.\n*   **Anamnesis y Exploración Oftalmológica (AO, EO):** Evalúa la salud ocular y la agudeza visual. La agudeza visual con corrección es OD 1.4 y OI 1.5. El dictamen parcial oftalmológico es \'APTO\' con la restricción de usar gafas o lentes de contacto (código 0106) para asegurar una agudeza visual binocular de al menos 0,5.\n*   **Anamnesis y Aptitud Psicológica (AP, EP, Aptitud Perceptivo-Motora, Trastornos Mentales):** Se evalúa el estado psicológico, la aptitud perceptivo-motora (atención, coordinación bimanual, tiempo de reacción) y la presencia de trastornos mentales. El informe indica que el individuo no presenta alteraciones en el área afectiva ni toma medicación psiquiátrica. El dictamen parcial psicológico es \'APTO\'.\n*   **Dictamen Final (DF):** Concluye que el individuo es \'APTO\' para la actividad evaluada, con la única restricción de \'Gafas o lentes de contacto\' (0106).\n\nEn resumen, este documento es una evaluación de salud para determinar la idoneidad de una persona, y no contiene ninguna información relevante para un análisis agronómico sobre especies agrícolas, plagas, cultivos o técnicas agrícolas.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_10_180_1777639943575.jpg','uploads/especies_pdfs/especie_10_1777639903719.pdf',1756745,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-05-01 12:52:03','2026-05-01 12:54:21','2026-05-01 12:54:21',NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(181,'documento','application/pdf','Documento_Web','Cultivo del Calabacín: Poda y Manejo','El documento del Ministerio de Agricultura, Pesca y Alimentación aborda el cultivo del calabacín, destacando que en condiciones normales de abonado y riego, la planta no requiere podas excesivas, desarrollando una única guía principal. Sin embargo, en situaciones de follaje abundante o ahijamiento, se recomienda la eliminación de tallos secundarios para evitar que los frutos de estos no alcancen tamaño comercial. Se enfatiza la importancia de podar estos brotes en su fase inicial, siempre respetando el tallo principal para mantener la productividad y calidad de la cosecha.','La poda en calabacín se reduce principalmente a la eliminación de tallos secundarios cuando la planta ahíja excesivamente debido a un abonado y riego intensivos.\nLos frutos que se desarrollan en los ramos secundarios suelen ser de tamaño no comercial, por lo que su eliminación temprana es crucial para concentrar la energía de la planta en la guía principal.\nEn cultivos normales, sin abusar de fertilizantes y agua, el calabacín tiende a desarrollar una sola guía, minimizando la necesidad de podas de formación.\nEl entutorado es una práctica complementaria a la poda, especialmente en invernadero, donde se ata el tallo principal a una cuerda para guiar su crecimiento vertical y optimizar el espacio y la luminosidad.\nLas temperaturas críticas para el calabacín incluyen la detención del crecimiento a 8°C y la helada a -1°C, mientras que la germinación óptima se da entre 20°C y 30°C, y el desarrollo óptimo a 25°C.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_10_181_1777640404975.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1973_07.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-01 12:54:58','2026-05-01 13:00:07',NULL,NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
