INSERT INTO `datosadjuntos` VALUES(194,'documento','application/pdf','Documento_Web','Poda apical en calabaza para frutos y semillas','Este estudio evalúa el efecto de la poda apical en la producción de frutos y semillas de calabaza (Cucurbita moschata). La poda busca equilibrar el desarrollo vegetativo, la floración y la fructificación, desviando auxinas hacia las yemas laterales para estimular su crecimiento. Se investigó la influencia de la poda en el sexto, octavo y décimo nudo de la rama principal, concluyendo que no hubo un impacto significativo en la productividad total de frutos y semillas, aunque sí en el número de ramas secundarias.','La poda apical, también conocida como desponte o capación, se realiza en la haste principal de cucurbitáceas para equilibrar el desarrollo de la planta.\nAltas concentraciones de auxina en el meristema apical se desvían a las gemas laterales tras la poda, promoviendo el crecimiento de ramas secundarias.\nEl estudio no encontró diferencias significativas en la producción de frutos y semillas de calabaza con la poda apical, aunque sí en el número de ramas secundarias.\nSe obtuvieron altas medias de germinación (94%) y productividad de frutos (16.9 t ha-1) y semillas (148 kg ha-1) en plantas no podadas.\nLa poda apical busca estimular la emisión de brotes laterales, lo que podría aumentar el número de flores femeninas y la fijación de frutos por planta.',NULL,NULL,'https://web.archive.org/web/2/https://www.cabidigitallibrary.org/doi/pdf/10.5555/20143325852',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-02 19:36:01',NULL,NULL,NULL,21,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
