INSERT INTO `datosadjuntos` VALUES(219,'documento','application/pdf','Documento_Web','Guía de Cultivo de Ajo del Ministerio Español','Este documento del Ministerio de Agricultura, Pesca y Alimentación de España ofrece una guía detallada sobre el cultivo del ajo, con un enfoque en la siembra. Destaca la importancia de seleccionar dientes sanos y grandes para la plantación. Se describen los marcos de plantación comunes, tanto para siembra manual como mecanizada, y las épocas de siembra según la variedad (ajo blanco en noviembre, ajo morado en diciembre o enero). También se mencionan las labores de preparación del terreno y la rotación de cultivos.','Para la siembra, se deben seleccionar dientes sanos, grandes y bien constituidos, siendo los procedentes de Chinchón, Bañolas y Las Pedroñeras de reconocida calidad.\nLa siembra en grandes extensiones se realiza de octubre a marzo, con el ajo blanco sembrándose en noviembre y el ajo morado en diciembre o enero.\nUn marco de plantación común es de líneas separadas 50 cm, con golpes de siembra a 15 cm en la línea; otro es de 0.8x0.3 metros.\nLa siembra puede ser manual (requiriendo unos 25 jornales/hectárea) o mediante plantadoras semimanuales o máquinas especializadas con cazoletas.\nSe recomienda una preparación profunda del terreno, especialmente si se siembra después de cereales, patatas o legumbres.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_14_219_1778313562233.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1984_01.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-06 19:59:35','2026-05-09 07:59:24',NULL,NULL,14,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
