INSERT INTO `datosadjuntos` VALUES(244,'documento','application/pdf','Documento_Web','Poda y Deshojado en Variedades de Calabacín para Industria','Este trabajo de fin de grado de la Universidad de Zaragoza explora la poda de formación y de brotes en calabacín, así como el deshojado, con un enfoque en la aptitud industrial de diferentes variedades. Aunque la poda de formación no es habitual, se sugiere la poda a dos brazos para potenciar la producción. Se enfatiza la eliminación de brotes secundarios en variedades híbridas y la importancia de un deshojado selectivo para mantener la sanidad y productividad de la planta, especialmente en la parte baja.','La poda de formación, aunque no estándar, puede realizarse cortando el tallo principal tras dos hojas verdaderas para inducir dos brazos secundarios y aumentar la producción.\nLa poda de brotes es esencial en variedades híbridas, ya que un exceso de nitrógeno puede generar brotes no productivos.\nEl deshojado debe efectuarse por la mañana, en ambiente seco, realizando cortes limpios en la unión del peciolo con el tallo, siempre por debajo de los frutos más bajos.\nEvitar podar las hojas superiores es crucial para proteger los frutos de la exposición solar directa y posibles quemaduras.\nTras cualquier poda, se recomienda aplicar tratamientos fungicidas para prevenir la entrada de patógenos a través de las heridas.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_10_244_1778252055718.jpg','https://web.archive.org/web/2/https://zaguan.unizar.es/record/76356/files/TAZ-TFG-2018-4730.pdf',0,NULL,NULL,NULL,NULL,0,2,NULL,1,'2026-05-08 14:53:48','2026-05-08 14:54:17',NULL,NULL,10,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
