INSERT INTO `datosadjuntos` VALUES(248,'documento','application/pdf','Manual de Buenas Prácticas de Riego','Manual de Buenas Prácticas de Riego','Este manual de WWF España se centra en el uso eficiente del agua en la agricultura, destacando la importancia de comprender el consumo hídrico de los cultivos a través de la evapotranspiración y las características del suelo. Propone un conjunto de buenas prácticas para minimizar las pérdidas de agua, mejorar la eficiencia de aplicación y asegurar una gestión hídrica sostenible. Aborda también el marco legal del uso del agua, la necesidad de un mantenimiento adecuado de los sistemas de riego y la adopción de tecnologías avanzadas para optimizar las decisiones de riego, buscando cosechas de calidad con el menor consumo de agua posible.','',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/labores_pdfs_covers/cover_1_248_1778314598850.jpg','http://awsassets.wwf.es/downloads/buenas_practicas_de_riego.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,0,'2026-05-08 18:58:23','2026-05-12 09:59:21','2026-05-12 09:59:21',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(249,'documento','application/pdf','Documento_Web','Manual Cultivo Espárrago (MAGYP)','Este manual detalla el cultivo del espárrago, abordando su origen, importancia económica y distribución global. Describe los requerimientos edafoclimáticos, incluyendo clima, iluminación y tipo de suelo ideal. Se enfoca en las particularidades del cultivo como la preparación del terreno, trasplante, siembra directa, manejo de malas hierbas, densidad de plantación, siega, abonado y riego. También cubre aspectos de plagas, enfermedades, fisiopatías, recolección y postcosecha, proporcionando una guía integral para su producción.','La densidad de plantación recomendada para espárrago verde en la zona de Médano de Oro es de 25,000 plantas/ha, con marcos de 1.25-1.50 x 0.30 m.\nEn el cultivo de espárrago verde, se prefieren plantas macho ya que no fructifican, evitando la multiplicación incontrolada de plantas y manteniendo la calidad de los turiones.\nEl trasplante puede ser de araña o plántula; con plántulas en cepellón, la producción de turiones puede iniciarse a los dos años, o al año en climas cálidos.\nLa siega debe realizarse cerca de la base del tallo, preferiblemente de forma mecanizada, una vez que la parte aérea comienza a secarse tras el periodo de aprovisionamiento de reservas.\nDurante la fase de recolección, es posible usar herbicidas sistémicos vía foliar, ya que solo afectan a los turiones emergidos y no a la parte subterránea de la planta.',NULL,NULL,'https://web.archive.org/web/2/https://www.magyp.gob.ar/normativa/_pdf/20211001150109.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-08 19:04:35',NULL,NULL,NULL,30,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
