INSERT INTO `datosadjuntos` VALUES(266,'documento','application/pdf','Manual de Riego y Manejo Hídrico de Cultivos','Manual de Riego y Manejo Hídrico de Cultivos','Este manual, elaborado por la Comisión Nacional de Riego de Chile y la Universidad de Concepción, está dirigido a pequeños productores agrícolas y agentes de extensión. Su objetivo es describir los principales métodos de riego utilizados en la pequeña agricultura, ofreciendo recomendaciones y soluciones técnicas para el uso de equipos y el manejo hídrico de cultivos. Busca optimizar el uso de recursos hídricos y aumentar la productividad predial, abordando el riego superficial, por aspersión y localizado, y enfatizando la importancia del conocimiento del suelo, topografía, cultivo y clima para un manejo adecuado.','',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/labores_pdfs_covers/cover_1_266_1778314701249.jpg','https://bibliotecadigital.ciren.cl/bitstream/handle/20.500.13082/32796/MANUAL.pdf',0,NULL,NULL,NULL,NULL,0,2,NULL,0,'2026-05-09 08:17:56','2026-05-12 09:59:12','2026-05-12 09:59:12',NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
