INSERT INTO `datosadjuntos` VALUES(271,'documento','application/pdf','Documento_Web','Producción de Tomate Cherry en Invernadero','Este documento, resultado de un taller en la Estación Experimental Agrícola Fabio Baudrit Moreno, aborda la producción de tomate cherry bajo invernadero. Cubre aspectos cruciales como el manejo del cultivo, la fertilización adecuada, el análisis del crecimiento de la planta, y la implementación de un manejo integrado de plagas. También se discuten criterios de calidad, técnicas de cosecha y la evaluación de diversas variedades de tomate cherry, incluyendo genotipos con diferentes colores y formas de fruto, y altos grados Brix. Se enfatiza la importancia de la investigación para la selección de genotipos óptimos en sistemas de invernadero.','El taller cubrió manejo del cultivo, fertilización, análisis de crecimiento, manejo integrado de plagas, criterios de calidad, cosecha y variedades de tomate cherry.\nSe evaluaron 63 genotipos de tomate, incluyendo variedades de crecimiento determinado e indeterminado, y frutos de colores (rojo, amarillo, anaranjado, morado) y formas (redondo, alargado, pera, fresa) variadas.\nMuchos genotipos sobresalientes producen frutos muy dulces, con valores Brix entre 9.0 y 13.0.\nSe discutió el comportamiento del cultivo bajo diferentes sistemas de sostén y se analizaron componentes del sistema hidropónico de producción.\nLa investigación busca desarrollar una metodología para la selección de genotipos de tomate cultivados bajo invernadero, basada en rendimiento y grados Brix.',NULL,NULL,'https://web.archive.org/web/2/https://www.researchgate.net/publication/342425601_Produccion_de_tomate_cherry_en_invernadero',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-11 15:16:36',NULL,NULL,NULL,2,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `datosadjuntos` VALUES(272,'documento','application/pdf','Documento_Web','Evaluación de Híbridos de Tomate Cherry en Ambiente Protegido','Este documento del Ministerio de Agricultura y Ganadería de Costa Rica evalúa la capacidad de producción y las cualidades de los frutos de dos híbridos de tomate cherry, Muscato y Natacha, cultivados bajo ambiente protegido en Puriscal. El estudio, realizado en un invernadero de 210 m², comparó variables como el rendimiento total por planta, el número de racimos y el peso promedio de los frutos. Se encontró que el híbrido Natacha superó significativamente a Muscato en rendimiento, lo que sugiere su potencial como alternativa de producción para diversificar la oferta tecnológica y aprovechar un nicho de mercado en la región. La investigación busca ampliar las opciones de cultivo de tomate cherry en condiciones protegidas, tanto en invierno como en verano.','Se evaluaron los híbridos de tomate cherry Muscato y Natacha bajo ambiente protegido en un invernadero de 210 m² en Puriscal, Costa Rica, entre octubre de 2004 y abril de 2005.\nEl híbrido Natacha mostró un rendimiento significativamente mayor (5.4 kg/planta) en comparación con Muscato (3.9 kg/planta), con una diferencia estadística (p < 0.01).\nLas diferencias en la producción se atribuyeron a que Natacha produjo más racimos por planta y frutos con un peso promedio de 15.04 g, frente a los 11.95 g de Muscato.\nEl estudio destaca la importancia de la producción de tomate cherry bajo ambiente protegido como una alternativa para diversificar la oferta tecnológica y aprovechar un nicho de mercado en la región.\nSe analizaron variables como rendimiento total en kilogramos por invernadero, número de plantas cosechadas y grados Brix de los frutos, utilizando pruebas de hipótesis de comparación directa entre medias (T de Student).',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/variedades_pdfs_covers/cover_2_272_1778512790370.jpg','https://web.archive.org/web/2/https://www.mag.go.cr/bibliotecavirtual/Ha-2006(Ano4-N1)p5.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-11 15:19:24','2026-05-11 15:19:55',NULL,NULL,NULL,2,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
