INSERT INTO `datosadjuntos` VALUES(277,'documento','application/pdf','Documento_Web','Poda y Entutorado del Tomate (Ministerio de Agricultura)','Este documento del Ministerio de Agricultura detalla las prácticas culturales esenciales para el cultivo intensivo de tomate, tanto en invernadero como al aire libre, enfocándose en la poda o destallado, despunte, deshojado y entutorado. Explica cómo estas operaciones son cruciales para limitar el número de tallos, mejorar la calidad y tamaño de los frutos, y aumentar la precocidad de la producción, a pesar de la mano de obra intensiva que requieren. Se abordan diferentes sistemas de poda para optimizar el rendimiento y la sanidad de la planta.','La poda o destallado busca encauzar el desarrollo vegetativo, limitando el número de tallos para obtener mayor precocidad y calidad de frutos, incluyendo mayor tamaño, uniformidad de color y tersura.\nLas ventajas de la poda incluyen mayor facilidad en las labores de cultivo, mejor control de plagas y enfermedades, mayor rapidez en la recolección y aumento de la producción por unidad de superficie.\nLa poda más común implica dejar el tallo principal y uno o dos brotes axilares, eliminando los demás hijuelos.\nSe describen sistemas de entutorado como soporte individual, pirámide, empalizada y caballete, siendo el entutorado con hilos de rafia común en invernaderos.\nEl documento advierte que un destallado muy enérgico puede causar desequilibrio fisiológico, resultando en abarquillamiento de hojas y una "parada" en el desarrollo vegetativo.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_3_277_1778580947745.jpg','https://web.archive.org/web/2/https://www.mapa.gob.es/ministerio/pags/biblioteca/hojas/hd_1973_19.pdf',0,NULL,NULL,NULL,NULL,0,1,NULL,1,'2026-05-12 10:15:18','2026-05-12 10:15:57',NULL,NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
