INSERT INTO `datosadjuntos` VALUES(398,'documento','application/pdf','Documento_Web','Riego por Goteo en Tomate: Cultivares y Láminas (UNA Nicaragua)','Esta investigación evalúa el impacto de diferentes láminas de riego por goteo en el rendimiento y calidad de cultivares de tomate (Shanty, UC-82 y Butero) bajo condiciones edafoclimáticas de Managua, Nicaragua. Se determinó que el consumo diario de agua por planta adulta oscila entre 1.5 y 2.0 litros, variando según la zona, variedad y clima. Los resultados indican que láminas de riego de 2.0 y 2.5 litros/planta/día produjeron los mayores rendimientos, con un coeficiente de uniformidad del 98.28% para el sistema de goteo.','El consumo diario de agua por planta adulta de tomate es de aproximadamente 1.5 a 2.0 litros, influenciado por la zona, variedad, clima y tipo de suelo.\nEl riego por goteo generalmente aplica entre 3 a 4 litros de agua por m² al día.\nEn el estudio, las láminas de riego de 2.0 y 2.5 litros/planta/día resultaron en los mayores rendimientos (11,875 kg/ha y 10,970 kg/ha, respectivamente).\nLos cultivares Shanty y Butero mostraron los mayores promedios de rendimiento en el ensayo.\nEl coeficiente de uniformidad del sistema de riego por goteo calculado fue del 98.28%, catalogado como excelente, lo que indica una distribución muy homogénea del agua.',NULL,'https://storage.googleapis.com/verdantia-494121.firebasestorage.app/uploads/especies_pdfs_covers/cover_3_398_1780075802936.jpg','https://web.archive.org/web/2/https://camjol.info/index.php/CALERA/article/view/9811',0,NULL,NULL,NULL,NULL,0,2,NULL,1,'2026-05-29 17:29:32','2026-05-29 17:30:05',NULL,NULL,3,NULL,NULL,NULL,NULL,NULL,NULL,1,NULL,NULL,NULL,NULL,NULL,NULL);
