INSERT INTO `especies` VALUES(10,'Calabacín','Cucurbita pepo','Cucurbitaceae','hortaliza','anual',7,20,'5.00','150.000',50,55,'10.00','24.00','80.00','120.00','2.50','El calabacín, una variedad de Cucurbita pepo, tiene sus orígenes en América, donde fue domesticado hace miles de años. Las evidencias arqueológicas sugieren que las cucurbitáceas se cultivaban en México desde el 7000 a.C., siendo una parte fundamental de la dieta de las civilizaciones precolombinas junto al maíz y las judías.\n\nFue introducido en Europa tras la llegada de Cristóbal Colón al continente americano, pero no fue hasta el siglo XIX en Italia cuando se seleccionaron y popularizaron las variedades de calabacín tal como las conocemos hoy, con frutos tiernos y de rápido crecimiento. Desde entonces, se ha extendido por todo el mundo, convirtiéndose en una hortaliza muy apreciada por su versatilidad culinaria y facilidad de cultivo.','El calabacín requiere pleno sol y suelos ricos en materia orgánica, bien drenados y con pH ligeramente ácido a neutro. Es fundamental un riego constante, especialmente durante la floración y fructificación, evitando encharcamientos. Se recomienda cosechar los frutos cuando son jóvenes y tiernos para estimular una producción continua y obtener la mejor calidad. La planta es vigorosa y puede requerir espacio considerable.','Verde','grande','2026-04-02 15:57:52',3,5,4,7,4,6,6,10,NULL,1,'https://es.wikipedia.org/wiki/Cucurbita_pepo,https://es.wikipedia.org/wiki/Agricultura_biodin%C3%A1mica','3.00','1.00','5.00','🟢','fruto','Las plantas de fruto se benefician de la siembra en días de fruto y el trasplante en fase descendente para enraizar mejor y asegurar una buena cosecha.','2.5','6.5 - 7.0','alta','directa,semillero,planton','directa,semillero',25,'pleno_sol','franco, rico en materia orgánica, bien drenado','baja',32,'Creciente','Menguante','Sembrar en luna creciente favorece el crecimiento aéreo y la fructificación. Trasplantar en luna menguante ayuda al enraizamiento y reduce el estrés. Evitar luna nueva y llena para siembra y trasplante.','Ascendente','Descendente',50,100,35,135);
INSERT INTO `especies` VALUES(11,'Pepino','Cucumis sativus','Cucurbitáceas','hortaliza,fruta','anual',8,NULL,'5.00',NULL,55,NULL,'12.00','25.00','40.00','100.00','2.00','Originario de la India, cultivado hace m+','Cultivo de porte rastrero/trepador famoso por su gran nivel de hidrataci+',NULL,NULL,'2026-04-02 15:57:52',3,5,4,6,4,5,6,9,NULL,1,NULL,NULL,NULL,NULL,'🥒',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `especies` VALUES(12,'Rábano','Raphanus sativus','Crucíferas','hortaliza','anual',5,NULL,'5.00',NULL,25,NULL,'5.00','18.00','5.00','20.00','1.00','Originario de China y Asia Central. Cultivado en Egipto y Grecia desde la antig++edad. Es una de las hortalizas de ciclo m+','Crecimiento mete+',NULL,NULL,'2026-04-02 15:57:52',0,0,1,12,NULL,NULL,2,12,NULL,1,NULL,NULL,NULL,NULL,'🌱',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `especies` VALUES(13,'Espinaca','Spinacia oleracea','Quenopodiáceas','hortaliza','anual,bianual',8,NULL,'4.00',NULL,40,NULL,'2.00','18.00','15.00','25.00','2.00','Originaria de Persia (actual Ir+','Hortaliza frondosa amigable con el clima fr+',NULL,NULL,'2026-04-02 15:57:52',0,0,8,2,NULL,NULL,10,4,NULL,1,NULL,NULL,NULL,NULL,'🍃',NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
INSERT INTO `especies` VALUES(14,'Ajos','Allium sativum','Amaryllidaceae','hortaliza,aromatica','anual',10,NULL,'1.00',NULL,240,NULL,NULL,'18.00','15.00','30.00','4.00','El ajo, Allium sativum, tiene sus orígenes en Asia Central, desde donde se extendió por todo el mundo. Su cultivo se remonta a más de 5.000 años, siendo una planta fundamental en la dieta y la medicina de civilizaciones antiguas como la egipcia, griega y romana, quienes lo valoraban por sus propiedades culinarias y medicinales.\n\nA lo largo de la historia, el ajo ha sido un ingrediente esencial en diversas culturas, utilizado no solo como condimento sino también como remedio para múltiples dolencias y como amuleto protector. Su adaptabilidad a diferentes climas y suelos facilitó su rápida difusión, consolidándose como un pilar de la gastronomía global.','El ajo requiere pleno sol y un suelo bien drenado, fértil y rico en materia orgánica. Se planta directamente a partir de dientes (bulbillos) en otoño o a finales de invierno, con la punta hacia arriba. Es crucial mantener una humedad constante, especialmente durante el desarrollo del bulbo, pero evitando el encharcamiento. La fertilización equilibrada es importante para un buen desarrollo. La recolección se realiza cuando las hojas inferiores comienzan a amarillear y secarse.','Blanco','mediano','2026-04-02 17:50:03',1,1,10,3,1,1,6,8,NULL,1,'https://es.wikipedia.org/wiki/Allium_sativum,https://es.wikipedia.org/wiki/Agricultura_biodin%C3%A1mica','70.00','25.00','110.00','🧄','raiz','Siembra y trasplante en días raíz para fomentar el desarrollo del bulbo. La recolección también es óptima en días raíz para una mejor conservación y sabor.',NULL,'6.0 - 7.0','media','directa',NULL,10,'pleno_sol','franco, bien drenado, rico en materia orgánica','baja',30,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL,NULL);
