INSERT INTO `especiesplagas` VALUES(30,14,8,'media','Las larvas atacan los bulbos y raíces, causando pudrición y marchitamiento.');
INSERT INTO `especiesplagas` VALUES(31,14,9,'alta','Provocan hinchazón y deformación de los bulbos y hojas, y pueden destruir la cosecha.');
INSERT INTO `especiesplagas` VALUES(32,14,10,'media','Se alimentan de las hojas, causando manchas plateadas y debilitando la planta.');
INSERT INTO `especiesplagas` VALUES(33,14,5,'media','Hongo que causa manchas amarillentas en las hojas que luego se vuelven necróticas.');
INSERT INTO `especiesplagas` VALUES(34,23,1,'media','Coloniza los brotes tiernos y el envés de las hojas, debilitando la planta.');
INSERT INTO `especiesplagas` VALUES(35,23,4,'baja','Aparece como un polvo blanco en las hojas, especialmente en condiciones de alta humedad y poca ventilación.');
INSERT INTO `especiesplagas` VALUES(36,23,12,'media','Pueden alimentarse de las hojas jóvenes y tiernas, especialmente en primavera.');
INSERT INTO `especiesplagas` VALUES(42,21,1,'alta','Coloniza brotes tiernos y hojas, debilitando la planta y transmitiendo virus.');
INSERT INTO `especiesplagas` VALUES(43,21,2,'media','Se alimenta de la savia y puede transmitir virus, causando melaza y fumagina.');
INSERT INTO `especiesplagas` VALUES(44,21,4,'alta','Hongo blanco en hojas, reduce la fotosíntesis y el vigor de la planta, afectando la producción.');
INSERT INTO `especiesplagas` VALUES(45,21,3,'media','Pequeños ácaros que causan manchas amarillas y telarañas finas en el envés de las hojas.');
INSERT INTO `especiesplagas` VALUES(46,21,13,'alta','Se alimenta de hojas, flores y frutos jóvenes, causando daños significativos y transmitiendo enfermedades.');
INSERT INTO `especiesplagas` VALUES(47,21,15,'alta','La larva perfora los tallos, causando marchitamiento repentino y la muerte de la planta.');
INSERT INTO `especiesplagas` VALUES(72,3,1,'alta','Coloniza brotes tiernos, deforma hojas, y puede transmitir virus.');
INSERT INTO `especiesplagas` VALUES(73,3,2,'alta','Se alimenta de la savia, debilita la planta y produce melaza que favorece el hongo negrilla.');
INSERT INTO `especiesplagas` VALUES(74,3,5,'alta','Hongo que causa manchas marrones en hojas y tallos, pudrición de frutos, especialmente en condiciones de humedad.');
INSERT INTO `especiesplagas` VALUES(75,3,4,'media','Hongo blanco pulverulento en hojas, reduce la fotosíntesis y el vigor de la planta.');
INSERT INTO `especiesplagas` VALUES(76,3,16,'alta','Larvas que excavan galerías en hojas, tallos y frutos, causando graves daños a la producción.');
INSERT INTO `especiesplagas` VALUES(77,3,17,'alta','Hongo que causa manchas oscuras y húmedas en hojas, tallos y frutos, llevando a la pudrición. Se favorece con alta humedad.');
INSERT INTO `especiesplagas` VALUES(78,3,3,'media','Causa decoloración y punteado en las hojas, y puede formar telarañas en el envés.');
INSERT INTO `especiesplagas` VALUES(79,10,1,'alta','Coloniza brotes tiernos y el envés de las hojas, debilitando la planta y transmitiendo virus.');
INSERT INTO `especiesplagas` VALUES(80,10,4,'alta','Hongo que se manifiesta como un polvo blanco en hojas y tallos, reduciendo la fotosíntesis.');
INSERT INTO `especiesplagas` VALUES(81,10,3,'media','Pequeños ácaros que causan manchas amarillas y telarañas finas en el envés de las hojas.');
INSERT INTO `especiesplagas` VALUES(82,10,2,'media','Insectos pequeños que se alimentan de la savia y excretan melaza, favoreciendo la fumagina.');
INSERT INTO `especiesplagas` VALUES(83,10,7,'media','Comen hojas jóvenes y pueden dañar los frutos cercanos al suelo.');
