INSERT INTO `laborespauta` VALUES(221,10,3,'presiembra',NULL,'Laboreo profundo para airear y preparar el suelo antes de la siembra.',1,NULL,NULL,-60,'ambos');
INSERT INTO `laborespauta` VALUES(222,3,3,'presiembra',NULL,'Abonado de fondo. Si usas materia orgánica (estiércol maduro/compost), incorpórala ahora a 20-30 cm de profundidad para que la tierra la asimile con tiempo. Si optas por fertilizante mineral NPK granulado, ignora esta tarea hoy y aplícalo justo en el momento de la siembra o preparación final.',1,NULL,NULL,-45,'ambos');
INSERT INTO `laborespauta` VALUES(223,12,3,'siembra',NULL,'Siembra directa de semillas o plantación de plántulas en semillero.',1,NULL,NULL,0,'semilla');
INSERT INTO `laborespauta` VALUES(224,1,3,'pregerminacion',2,'Riegos ligeros y frecuentes para mantener la humedad del sustrato hasta la emergencia.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(225,1,3,'germinacion',1,'Riego muy suave para no dañar las plántulas recién emergidas.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(226,1,3,'crecimiento_inicial',3,'Riego regular, adaptado a la demanda de las plántulas jóvenes, evitando encharcamientos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(227,2,3,'crecimiento_inicial',14,'Control manual o mecánico de malas hierbas para evitar competencia con las plántulas.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(228,3,3,'crecimiento_inicial',10,'Fertilización foliar o ligera para estimular el desarrollo inicial de la planta.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(229,13,3,'trasplante',NULL,'Trasplante de las plántulas al lugar definitivo de cultivo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(230,1,3,'trasplante',1,'Riego abundante inmediatamente después del trasplante para favorecer el enraizamiento.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(231,1,3,'crecimiento',2,'Riego frecuente y profundo, ajustado a la demanda de la planta en desarrollo vegetativo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(232,3,3,'crecimiento',7,'Fertilización equilibrada para un fuerte desarrollo vegetativo y estructural.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(233,2,3,'crecimiento',10,'Mantenimiento del cultivo libre de malas hierbas para optimizar recursos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(234,5,3,'crecimiento',14,'Sujeción de la planta a tutores a medida que crece para evitar caídas y mejorar aireación.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(235,4,3,'crecimiento',10,'Eliminación de chupones (brotes axilares) y hojas bajas para enfocar la energía en el tallo principal.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(236,8,3,'crecimiento',NULL,'Aplicación de acolchado para conservar la humedad del suelo, controlar malas hierbas y regular temperatura.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(237,6,3,'crecimiento',14,'Aplicación preventiva o curativa de tratamientos fitosanitarios según la presencia de plagas/enfermedades.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(238,1,3,'fructificacion',1,'Riego constante y preciso, crucial para el cuajado, desarrollo y engorde de los frutos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(239,3,3,'fructificacion',5,'Fertilización rica en potasio y otros micronutrientes para la formación y calidad de los frutos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(240,4,3,'fructificacion',7,'Deshojado estratégico y eliminación de chupones para mejorar la ventilación y la exposición solar de los frutos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(241,5,3,'fructificacion',21,'Refuerzo del entutorado debido al peso creciente de los frutos en la planta.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(242,7,3,'fructificacion',NULL,'Eliminación de frutos pequeños o deformes para concentrar la energía en los frutos de mayor calidad.',1,NULL,NULL,15,'ambos');
INSERT INTO `laborespauta` VALUES(243,6,3,'fructificacion',7,'Control estricto de plagas y enfermedades, priorizando productos de bajo impacto en la fase de fructificación.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(244,9,3,'recoleccion',3,'Recolección periódica de los frutos maduros para estimular la producción continua.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(245,1,3,'recoleccion',2,'Mantener el riego adecuado para sostener la planta durante el periodo de producción.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(246,3,3,'recoleccion',14,'Fertilización de mantenimiento para asegurar la continuidad de la producción de frutos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(247,10,3,'finalizacion',NULL,'Laboreo del terreno para incorporar restos vegetales y preparar para el siguiente ciclo de cultivo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(248,11,3,'finalizacion',NULL,'Arranque y eliminación de los restos de plantas enfermas o al final de su ciclo productivo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(249,10,14,'presiembra',NULL,'Laboreo profundo para descompactar el suelo, mejorar la aireación y drenaje antes de la siembra.',1,NULL,NULL,-30,'ambos');
INSERT INTO `laborespauta` VALUES(250,3,14,'presiembra',NULL,'Incorporación de abono orgánico o de fondo rico en fósforo y potasio para preparar el suelo.',1,NULL,NULL,-20,'ambos');
INSERT INTO `laborespauta` VALUES(251,1,14,'presiembra',NULL,'Riego ligero para asegurar la humedad adecuada del suelo antes de la plantación de los dientes.',1,NULL,NULL,-5,'ambos');
INSERT INTO `laborespauta` VALUES(252,12,14,'siembra',NULL,'Plantación de los dientes de ajo a la profundidad y distancia adecuadas para un óptimo desarrollo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(253,1,14,'pregerminacion',4,'Riegos frecuentes y ligeros para mantener la humedad del suelo y favorecer la brotación de los ajos.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(254,2,14,'crecimiento_inicial',15,'Primer escardado manual o mecánico para eliminar malas hierbas competidoras en las primeras etapas.',1,NULL,NULL,15,'ambos');
INSERT INTO `laborespauta` VALUES(255,1,14,'crecimiento_inicial',7,'Riegos regulares para asegurar el desarrollo inicial de las plántulas de ajo.',1,NULL,NULL,10,'ambos');
INSERT INTO `laborespauta` VALUES(256,3,14,'crecimiento',NULL,'Primer abonado de cobertera, rico en nitrógeno para promover el desarrollo vegetativo de la planta.',1,NULL,NULL,30,'ambos');
INSERT INTO `laborespauta` VALUES(257,2,14,'crecimiento',20,'Escardas periódicas para mantener el cultivo libre de malas hierbas, evitando competencia por nutrientes.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(258,1,14,'crecimiento',7,'Aumentar la frecuencia y volumen de riego a medida que la planta crece y demanda más agua.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(259,6,14,'crecimiento',30,'Aplicación preventiva o curativa de fitosanitarios contra plagas y enfermedades comunes del ajo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(260,3,14,'fructificacion',NULL,'Segundo abonado de cobertera, con énfasis en potasio para el engorde y desarrollo del bulbo.',1,NULL,NULL,15,'ambos');
INSERT INTO `laborespauta` VALUES(261,1,14,'fructificacion',10,'Reducir gradualmente el riego para favorecer la maduración y el secado adecuado del bulbo de ajo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(262,2,14,'fructificacion',30,'Último escardado para evitar competencia de malas hierbas y facilitar las labores de cosecha.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(263,9,14,'recoleccion',NULL,'Cosecha de los ajos cuando las hojas inferiores amarillean y se secan, indicando su madurez.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(264,10,14,'finalizacion',NULL,'Laboreo superficial para limpiar el terreno de restos de cultivo y preparar para el siguiente ciclo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(265,3,3,'siembra',NULL,'Aporte extra de materia orgánica (humus de lombriz/harina de hueso) directamente en el hoyo de plantación para un enraizamiento vigoroso. Si en su lugar optas por un abonado de fondo mineral (NPK granulado), este es el momento exacto para aplicarlo, mezclándolo bien con la tierra del fondo antes de meter la planta.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(266,10,3,'siembra',NULL,'Si ya realizaste el laboreo profundo hace semanas, haz hoy solo un laboreo superficial para mullir la tierra y eliminar adventicias justo antes de plantar. Si NO pudiste realizar aquel laboreo previo, debes remover la tierra profundamente ahora (a 20-30 cm de profundidad) para prepararla adecuadamente.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(267,8,3,'siembra',NULL,'Colocar un acolchado (mulch) orgánico (paja, hojas secas, restos de poda) o plástico alrededor de la base de la planta recién instalada. Esto es vital en el tomate para retener la humedad del suelo, evitar malas hierbas y proteger las raíces de las variaciones térmicas.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(268,1,3,'siembra',NULL,'Riego de asentamiento. Inmediatamente después de colocar la semilla o el plantón y aplicar el acolchado, aplica un riego muy generoso (preferiblemente en forma de lluvia fina) para asentar bien la tierra, eliminar las bolsas de aire de las raíces y estimular el inicio del ciclo.',1,NULL,NULL,0,'ambos');
INSERT INTO `laborespauta` VALUES(269,13,3,'presiembra',NULL,NULL,1,NULL,NULL,0,'planton');
INSERT INTO `laborespauta` VALUES(270,13,3,'siembra',NULL,'Trasplante del plantón al lugar definitivo. En el tomate es recomendable enterrar parte del tallo desnudo para favorecer el desarrollo de raíces adventicias secundarias.',1,NULL,NULL,0,'planton');
