  `especiestemperaturaminima` decimal(8,2) DEFAULT NULL,
  `especiestemperaturaoptima` decimal(8,2) DEFAULT NULL,
  `especiesmarcoplantas` decimal(8,2) DEFAULT NULL,
  `especiesmarcofilas` decimal(8,2) DEFAULT NULL,
  `especiesprofundidadsiembra` decimal(8,2) DEFAULT NULL,
  `especieshistoria` text DEFAULT NULL,
  `especiesdescripcion` text DEFAULT NULL,
  `especiescolor` varchar(50) DEFAULT NULL,
  `especiestamano` enum('pequeno','mediano','grande') DEFAULT 'mediano',
  `especiesfechacreacion` timestamp NOT NULL DEFAULT current_timestamp(),
  `especiesfechasemillerodesde` int(11) DEFAULT NULL,
  `especiesfechasemillerohasta` int(11) DEFAULT NULL,
  `especiesfechasiembradirectadesde` int(11) DEFAULT NULL,
  `especiesfechasiembradirectahasta` int(11) DEFAULT NULL,
  `especiestrasplantedesde` int(11) DEFAULT NULL,
  `especiestrasplantehasta` int(11) DEFAULT NULL,
  `especiesfecharecolecciondesde` int(11) DEFAULT NULL,
  `especiesfecharecoleccionhasta` int(11) DEFAULT NULL,
  `xespeciesidusuarios` int(11) DEFAULT NULL,
  `especiesvisibilidadsino` tinyint(1) DEFAULT 1,
  `especiesfuentesinformacion` text DEFAULT NULL,
  `especiesautosuficiencia` decimal(8,2) DEFAULT NULL,
  `especiesautosuficienciaparcial` decimal(10,2) DEFAULT NULL,
  `especiesautosuficienciaconserva` decimal(8,2) DEFAULT NULL,
  `especiesicono` varchar(20) DEFAULT NULL,
  `especiesbiodinamicacategoria` varchar(50) DEFAULT NULL,
  `especiesbiodinamicanotas` text DEFAULT NULL,
  `especiesprofundidadtrasplante` varchar(50) DEFAULT NULL,
  `especiesphsuelo` varchar(50) DEFAULT NULL,
  `especiesnecesidadriego` varchar(50) DEFAULT NULL,
  `especiestiposiembra` varchar(255) DEFAULT NULL,
  `especiestiposiembrapreferente` varchar(255) DEFAULT NULL,
  `especiesvolumenmaceta` int(11) DEFAULT NULL,
  `especiesluzsolar` varchar(50) DEFAULT NULL,
  `especiescaracteristicassuelo` varchar(255) DEFAULT NULL,
  `especiesdificultad` varchar(50) DEFAULT NULL,
  `especiestemperaturamaxima` int(11) DEFAULT NULL,
  `especieslunarfasesiembra` varchar(100) DEFAULT NULL,
  `especieslunarfasetrasplante` varchar(100) DEFAULT NULL,
  `especieslunarobservaciones` text DEFAULT NULL,
  `especiesbiodinamicafasesiembra` varchar(100) DEFAULT NULL,
  `especiesbiodinamicafasetrasplante` varchar(100) DEFAULT NULL,
  `especiesemillerovolumendesde` int(11) DEFAULT NULL,
  `especiesemillerovolumenhasta` int(11) DEFAULT NULL,
  `especiesdiascrecimientofirme` int(11) DEFAULT NULL,
  `especiesduraciontotal` int(11) DEFAULT NULL,
  PRIMARY KEY (`idespecies`),
  UNIQUE KEY `nombre` (`especiesnombre`)
) ENGINE=InnoDB AUTO_INCREMENT=45 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `especiesplagas`;
CREATE TABLE `especiesplagas` (
  `idespeciesplagas` int(11) NOT NULL AUTO_INCREMENT,
  `xespeciesplagasidespecies` int(11) NOT NULL,
  `xespeciesplagasidplagas` int(11) NOT NULL,
  `especiesplagasnivelriesgo` varchar(50) DEFAULT NULL,
  `especiesplagasnotasespecificas` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`idespeciesplagas`),
  KEY `xespeciesplagasidespecies` (`xespeciesplagasidespecies`),
  KEY `xespeciesplagasidplagas` (`xespeciesplagasidplagas`),
  CONSTRAINT `especiesplagas_ibfk_1` FOREIGN KEY (`xespeciesplagasidespecies`) REFERENCES `especies` (`idespecies`) ON DELETE CASCADE,
  CONSTRAINT `especiesplagas_ibfk_2` FOREIGN KEY (`xespeciesplagasidplagas`) REFERENCES `plagas` (`idplagas`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=84 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `especiessinonimos`;
CREATE TABLE `especiessinonimos` (
  `idespeciessinonimos` int(11) NOT NULL AUTO_INCREMENT,
  `xespeciessinonimosidespecies` int(11) NOT NULL,
  `xespeciessinonimosididiomas` int(11) DEFAULT NULL,
  `xespeciessinonimosidpaises` int(11) DEFAULT NULL,
  `especiessinonimosnombre` varchar(100) NOT NULL,
  `especiessinonimosnotas` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`idespeciessinonimos`),
  KEY `xespeciessinonimosididiomas` (`xespeciessinonimosididiomas`),
  KEY `xespeciessinonimosidpaises` (`xespeciessinonimosidpaises`),
  CONSTRAINT `especiessinonimos_ibfk_1` FOREIGN KEY (`xespeciessinonimosididiomas`) REFERENCES `idiomas` (`ididiomas`) ON DELETE SET NULL,
  CONSTRAINT `especiessinonimos_ibfk_2` FOREIGN KEY (`xespeciessinonimosidpaises`) REFERENCES `paises` (`idpaises`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=180 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `especiesusuarios`;
CREATE TABLE `especiesusuarios` (
  `idespeciesusuarios` int(11) NOT NULL AUTO_INCREMENT,
  `xespeciesusuariosidusuarios` int(11) DEFAULT NULL,
  `xespeciesusuariosidespecies` int(11) DEFAULT NULL,
  `especiesusuariosnombre` varchar(100) DEFAULT NULL,
  `especiesusuariosnombrecientifico` varchar(200) DEFAULT NULL,
  `especiesusuariosfamilia` varchar(100) DEFAULT NULL,
  `especiesusuariostipo` set('hortaliza','fruta','aromatica','leguminosa','cereal') DEFAULT NULL,
  `especiesusuariosciclo` set('anual','bianual','perenne') DEFAULT NULL,
  `especiesusuarioshistoria` text DEFAULT NULL,
  `especiesusuariosdescripcion` text DEFAULT NULL,
  `especiesusuarioscolor` varchar(50) DEFAULT NULL,
  `especiesusuariostamano` enum('pequeno','mediano','grande') DEFAULT NULL,
  `especiesusuariosfuentesinformacion` text DEFAULT NULL,
  `especiesusuariosactivosino` tinyint(1) DEFAULT NULL,
  `especiesusuariosviabilidadsemilla` decimal(8,2) DEFAULT NULL,
  `especiesusuariossemillerodesde` int(11) DEFAULT NULL,
  `especiesusuariossemillerohasta` int(11) DEFAULT NULL,
  `especiesusuariossiembredirectadesde` int(11) DEFAULT NULL,
  `especiesusuariossiembradirectahasta` int(11) DEFAULT NULL,
  `especiesusuariostrasplantedesde` int(11) DEFAULT NULL,
  `especiesusuariostrasplantehasta` int(11) DEFAULT NULL,
  `especiesusuariosrecolecciondesde` int(11) DEFAULT NULL,
  `especiesusuariosrecoleccionhasta` int(11) DEFAULT NULL,
  `especiesusuariosdiashastafructificacion` int(11) DEFAULT NULL,
  `especiesusuariostemperaturaminima` decimal(8,2) DEFAULT NULL,
  `especiesusuariostemperaturaoptima` decimal(8,2) DEFAULT NULL,
  `especiesusuariosmarcoplantas` decimal(8,2) DEFAULT NULL,
  `especiesusuariosmarcofilas` decimal(8,2) DEFAULT NULL,
  `especiesusuariosprofundidadsiembra` decimal(8,2) DEFAULT NULL,
  `especiesusuariosautosuficiencia` decimal(8,2) DEFAULT NULL,
  `especiesusuariosautosuficienciaconserva` decimal(8,2) DEFAULT NULL,
  `especiesusuariosdiasgerminacion` int(11) DEFAULT NULL,
  PRIMARY KEY (`idespeciesusuarios`),
  UNIQUE KEY `usuario_id` (`xespeciesusuariosidusuarios`,`xespeciesusuariosidespecies`)
) ENGINE=InnoDB AUTO_INCREMENT=50 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `idiomas`;
CREATE TABLE `idiomas` (
  `ididiomas` int(11) NOT NULL AUTO_INCREMENT,
  `idiomasnombre` varchar(100) NOT NULL,
  `idiomasiso` varchar(10) DEFAULT NULL,
  PRIMARY KEY (`ididiomas`)
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `incidencias`;
CREATE TABLE `incidencias` (
  `idincidencias` int(11) NOT NULL AUTO_INCREMENT,
  `incidenciastipo` enum('foto_rechazada','foto_eliminada','chat_denuncia','chat_sancion','cuenta_suspension','cuenta_baja','contenido_inapropiado','spam','otro') NOT NULL,
  `incidenciassancion` enum('advertencia_1','advertencia_2','baja') DEFAULT NULL,
  `incidenciasestado` varchar(50) DEFAULT 'pendiente',
  `xincidenciasidusuarios` int(11) DEFAULT NULL,
  `incidenciasusuarioemail` varchar(255) NOT NULL,
  `incidenciasadminemail` varchar(255) DEFAULT NULL,
  `incidenciasreferenciaid` int(11) DEFAULT NULL,
  `incidenciasreferenciatipo` varchar(50) DEFAULT NULL,
  `incidenciasreferenciaruta` text DEFAULT NULL,
  `incidenciasmotivo` text DEFAULT NULL,
  `incidenciasrecurso` text DEFAULT NULL,
  `incidenciasnotas` text DEFAULT NULL,
  `incidenciasfechacreacion` datetime NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`idincidencias`),
  KEY `idx_usuario` (`xincidenciasidusuarios`),
  KEY `idx_tipo` (`incidenciastipo`),
  KEY `idx_estado` (`incidenciasestado`)
) ENGINE=InnoDB AUTO_INCREMENT=21 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `labores`;
CREATE TABLE `labores` (
  `idlabores` int(11) NOT NULL AUTO_INCREMENT,
  `laboresnombre` varchar(100) NOT NULL,
  `laboresdescripcion` text DEFAULT NULL,
  `laboresicono` varchar(50) DEFAULT 'mdi-tools',
  `laborescolor` varchar(20) DEFAULT '#64748b',
  `laboresactivosino` tinyint(1) DEFAULT 1,
  `laboresfechacreacion` timestamp NOT NULL DEFAULT current_timestamp(),
  `laboresnotificable` tinyint(1) DEFAULT 1,
  PRIMARY KEY (`idlabores`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;


DROP TABLE IF EXISTS `laborespauta`;
CREATE TABLE `laborespauta` (
  `idlaborespauta` int(11) NOT NULL AUTO_INCREMENT,
  `xlaborespautaidlabores` int(11) NOT NULL,
  `xlaborespautaidespecies` int(11) NOT NULL,
  `laborespautafase` varchar(50) NOT NULL COMMENT 'Ej: germinacion, crecimiento, floracion, fructificacion',
  `laborespautafrecuenciadias` int(11) DEFAULT NULL COMMENT 'Cada cuántos días se realiza',
  `laborespautanotasia` text DEFAULT NULL COMMENT 'Explicación IA',
  `laborespautaactivosino` tinyint(1) DEFAULT 1 COMMENT '1 = Activa, 0 = Inactiva',
  `xlaborespautaidusuarios` int(11) DEFAULT NULL,
  `xlaborespautaidvariedades` int(11) DEFAULT NULL,
  `laborespautaoffset` int(11) NOT NULL DEFAULT 0,
  `laborespautametodo` varchar(20) NOT NULL DEFAULT 'ambos',
  PRIMARY KEY (`idlaborespauta`),
  UNIQUE KEY `unique_laborespauta_rel` (`xlaborespautaidlabores`,`xlaborespautaidespecies`,`laborespautafase`),
  KEY `xlaborespautaidespecies` (`xlaborespautaidespecies`),
  KEY `idx_laborespauta_usuario` (`xlaborespautaidusuarios`),
  KEY `fk_laborespauta_variedad` (`xlaborespautaidvariedades`),
  CONSTRAINT `fk_laborespauta_usuario` FOREIGN KEY (`xlaborespautaidusuarios`) REFERENCES `usuarios` (`idusuarios`) ON DELETE CASCADE,
  CONSTRAINT `fk_laborespauta_variedad` FOREIGN KEY (`xlaborespautaidvariedades`) REFERENCES `variedades` (`idvariedades`) ON DELETE CASCADE,
  CONSTRAINT `laborespauta_ibfk_1` FOREIGN KEY (`xlaborespautaidlabores`) REFERENCES `labores` (`idlabores`) ON DELETE CASCADE,
  CONSTRAINT `laborespauta_ibfk_2` FOREIGN KEY (`xlaborespautaidespecies`) REFERENCES `especies` (`idespecies`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=271 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `laboresrealizadas`;
CREATE TABLE `laboresrealizadas` (
  `idlaboresrealizadas` int(11) NOT NULL AUTO_INCREMENT,
  `xlaboresrealizadasidcultivos` int(11) NOT NULL,
  `xlaboresrealizadasidlabores` int(11) NOT NULL,
  `laboresrealizadasfecha` date NOT NULL,
  `laboresrealizadasobservaciones` text DEFAULT NULL,
  `laboresrealizadasfechacreacion` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`idlaboresrealizadas`),
  KEY `xlaboresrealizadasidcultivos` (`xlaboresrealizadasidcultivos`),
  KEY `xlaboresrealizadasidlabores` (`xlaboresrealizadasidlabores`),
  CONSTRAINT `laboresrealizadas_ibfk_1` FOREIGN KEY (`xlaboresrealizadasidcultivos`) REFERENCES `cultivos` (`idcultivos`) ON DELETE CASCADE,
  CONSTRAINT `laboresrealizadas_ibfk_2` FOREIGN KEY (`xlaboresrealizadasidlabores`) REFERENCES `labores` (`idlabores`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `logros`;
CREATE TABLE `logros` (
  `idlogros` int(11) NOT NULL AUTO_INCREMENT,
  `logrosnivel` int(11) NOT NULL,
  `logrosnombre` varchar(100) NOT NULL,
  `logrosdescripcion` text DEFAULT NULL,
  `logrosicono` varchar(255) DEFAULT NULL,
  `req_antiguedad_meses` int(11) DEFAULT 0,
  `req_semillas` int(11) DEFAULT 0,
  `req_siembras` int(11) DEFAULT 0,
  `req_recolecciones` int(11) DEFAULT 0,
  `req_especies` int(11) DEFAULT 0,
  `req_fotos` int(11) DEFAULT 0,
  `req_mensajes` int(11) DEFAULT 0,
  `req_blogs` int(11) DEFAULT 0,
  `privilegios` text DEFAULT NULL,
  `descuento_pro` int(11) DEFAULT 0,
  `req_mantenimiento_mensual` int(11) DEFAULT 0,
  PRIMARY KEY (`idlogros`),
  UNIQUE KEY `logrosnivel` (`logrosnivel`),
  UNIQUE KEY `logrosnombre` (`logrosnombre`)
) ENGINE=InnoDB AUTO_INCREMENT=11 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `paises`;
CREATE TABLE `paises` (
  `idpaises` int(11) NOT NULL AUTO_INCREMENT,
  `paisesnombre` varchar(100) NOT NULL,
  `paisesisocode` varchar(10) DEFAULT NULL,
  PRIMARY KEY (`idpaises`)
) ENGINE=InnoDB AUTO_INCREMENT=38 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `plagas`;
CREATE TABLE `plagas` (
  `idplagas` int(11) NOT NULL AUTO_INCREMENT,
  `plagasnombre` varchar(100) NOT NULL,
  `plagasnombrecientifico` varchar(100) DEFAULT NULL,
  `plagastipo` varchar(50) DEFAULT NULL,
  `plagasdescripcion` text DEFAULT NULL,
  `plagascontrolorganico` text DEFAULT NULL,
  PRIMARY KEY (`idplagas`)
) ENGINE=InnoDB AUTO_INCREMENT=19 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `recolecciones`;
CREATE TABLE `recolecciones` (
  `idrecolecciones` int(11) NOT NULL AUTO_INCREMENT,
  `xrecoleccionesidusuarios` int(11) NOT NULL,
  `xrecoleccionesidcultivos` int(11) NOT NULL,
  `recoleccionesfecha` date NOT NULL,
  `recoleccionescantidad` decimal(8,2) DEFAULT NULL,
  `recoleccionesunidad` enum('kg','g','unidades','manojos') DEFAULT 'unidades',
  `recoleccionescalidad` enum('excelente','buena','regular','mala') DEFAULT 'buena',
  `recoleccionesobservaciones` text DEFAULT NULL,
  `recoleccionesfechacreacion` timestamp NOT NULL DEFAULT current_timestamp(),
  PRIMARY KEY (`idrecolecciones`),
  KEY `xrecoleccionesidusuarios` (`xrecoleccionesidusuarios`),
  KEY `xrecoleccionesidcultivos` (`xrecoleccionesidcultivos`),
  CONSTRAINT `recolecciones_ibfk_1` FOREIGN KEY (`xrecoleccionesidusuarios`) REFERENCES `usuarios` (`idusuarios`) ON DELETE CASCADE,
  CONSTRAINT `recolecciones_ibfk_2` FOREIGN KEY (`xrecoleccionesidcultivos`) REFERENCES `cultivos` (`idcultivos`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;

DROP TABLE IF EXISTS `semillas`;
CREATE TABLE `semillas` (
  `idsemillas` int(11) NOT NULL AUTO_INCREMENT,
  `xsemillasidusuarios` int(11) NOT NULL,
  `xsemillasidvariedades` int(11) NOT NULL,
  `semillasnumerocoleccion` int(11) DEFAULT NULL,
  `semillasorigen` enum('cosecha_propia','sobre_comprado','intercambio','regalada') NOT NULL DEFAULT 'sobre_comprado',
  `semillaslugarcompra` varchar(150) DEFAULT NULL,
  `semillasmarca` varchar(150) DEFAULT NULL,
  `semillasfecharecoleccion` date DEFAULT NULL,
  `semillasfechaenvasado` date DEFAULT NULL,
  `semillasfechacaducidad` date DEFAULT NULL,
  `semillaslote` varchar(60) DEFAULT NULL,
  `semillasstock` enum('abundante','medio','escaso','agotado') DEFAULT 'medio',
  `semillasobservaciones` text DEFAULT NULL,
  `semillasactivosino` tinyint(1) NOT NULL DEFAULT 1,
  `semillasfechacreacion` timestamp NOT NULL DEFAULT current_timestamp(),
  `semillasfechaactualizacion` timestamp NOT NULL DEFAULT current_timestamp() ON UPDATE current_timestamp(),
  `semillasstockactual` int(11) DEFAULT NULL,
  `semillasstockinicial` int(11) DEFAULT NULL,
  PRIMARY KEY (`idsemillas`),
  KEY `xsemillasidusuarios` (`xsemillasidusuarios`),
  KEY `xsemillasidvariedades` (`xsemillasidvariedades`),
  CONSTRAINT `semillas_ibfk_1` FOREIGN KEY (`xsemillasidusuarios`) REFERENCES `usuarios` (`idusuarios`) ON DELETE CASCADE,
  CONSTRAINT `semillas_ibfk_2` FOREIGN KEY (`xsemillasidvariedades`) REFERENCES `variedades` (`idvariedades`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=15 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `suscripciones`;
CREATE TABLE `suscripciones` (
  `idsuscripciones` int(11) NOT NULL AUTO_INCREMENT,
