DROP TABLE IF EXISTS `suscripcionesavisos`;
CREATE TABLE `suscripcionesavisos` (
  `idsuscripcionesavisos` int(11) NOT NULL AUTO_INCREMENT,
  `xsuscripcionesavisosidusuarios` int(11) DEFAULT NULL,
  `xsuscripcionesavisosidavisosglobales` int(11) DEFAULT NULL,
  `suscripcionesavisosactivosino` tinyint(1) DEFAULT NULL,
  `suscripcionesavisosfrecuencia` int(11) DEFAULT NULL,
