  PRIMARY KEY (`idsuscripcionesavisos`),
  UNIQUE KEY `u_aviso` (`xsuscripcionesavisosidusuarios`,`xsuscripcionesavisosidavisosglobales`),
  KEY `aviso_global_id` (`xsuscripcionesavisosidavisosglobales`),
  CONSTRAINT `suscripcionesavisos_ibfk_1` FOREIGN KEY (`xsuscripcionesavisosidusuarios`) REFERENCES `usuarios` (`idusuarios`) ON DELETE CASCADE,
  CONSTRAINT `suscripcionesavisos_ibfk_2` FOREIGN KEY (`xsuscripcionesavisosidavisosglobales`) REFERENCES `avisosglobales` (`idavisosglobales`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

DROP TABLE IF EXISTS `suscripcionescaracteristicas`;
CREATE TABLE `suscripcionescaracteristicas` (
  `idsuscripcionescaracteristicas` int(11) NOT NULL AUTO_INCREMENT,
  `suscripcionescaracteristicasclave` varchar(80) NOT NULL,
  `suscripcionescaracteristicastipo` enum('booleano','entero','cadena') NOT NULL DEFAULT 'booleano',
  `suscripcionescaracteristicasdescripcion` varchar(255) DEFAULT NULL,
  PRIMARY KEY (`idsuscripcionescaracteristicas`),
  UNIQUE KEY `uq_caracteristicas_clave` (`suscripcionescaracteristicasclave`)
) ENGINE=InnoDB AUTO_INCREMENT=14 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `suscripcioneslimites`;
CREATE TABLE `suscripcioneslimites` (
  `idsuscripcioneslimites` int(11) NOT NULL AUTO_INCREMENT,
  `xsuscripcioneslimitesidsuscripciones` int(11) NOT NULL,
  `xsuscripcioneslimitesidsuscripcionescaracteristicas` int(11) NOT NULL,
  `suscripcioneslimitesvalor` varchar(50) NOT NULL DEFAULT '0',
  PRIMARY KEY (`idsuscripcioneslimites`),
  UNIQUE KEY `uq_limites_plan_caract` (`xsuscripcioneslimitesidsuscripciones`,`xsuscripcioneslimitesidsuscripcionescaracteristicas`),
  KEY `fk_limites_caracteristica` (`xsuscripcioneslimitesidsuscripcionescaracteristicas`),
  CONSTRAINT `fk_limites_caracteristica` FOREIGN KEY (`xsuscripcioneslimitesidsuscripcionescaracteristicas`) REFERENCES `suscripcionescaracteristicas` (`idsuscripcionescaracteristicas`) ON DELETE CASCADE,
  CONSTRAINT `fk_limites_suscripcion` FOREIGN KEY (`xsuscripcioneslimitesidsuscripciones`) REFERENCES `suscripciones` (`idsuscripciones`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=40 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `suscripcionestiposavisos`;
CREATE TABLE `suscripcionestiposavisos` (
  `idsuscripcionestiposavisos` int(11) NOT NULL AUTO_INCREMENT,
  `xsuscripcionestiposavisosidsuscripciones` int(11) NOT NULL,
  `xsuscripcionestiposavisosidtiposavisos` int(11) NOT NULL,
  `suscripcionestiposavisosestado` int(11) NOT NULL DEFAULT 0 COMMENT '0: Opcional, 1: Obligatorio, 2: Bloqueado',
  PRIMARY KEY (`idsuscripcionestiposavisos`),
  UNIQUE KEY `susc_tipoaviso_UNIQUE` (`xsuscripcionestiposavisosidsuscripciones`,`xsuscripcionestiposavisosidtiposavisos`)
) ENGINE=InnoDB AUTO_INCREMENT=43 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `tiposavisos`;
CREATE TABLE `tiposavisos` (
  `idtiposavisos` int(11) NOT NULL AUTO_INCREMENT,
  `tiposavisoscodigo` varchar(50) NOT NULL,
  `tiposavisosnombre` varchar(100) NOT NULL,
  `tiposavisosdescripcion` varchar(255) DEFAULT NULL,
  `tiposavisosactivo` tinyint(1) NOT NULL DEFAULT 1,
  `tiposavisosmetodo` varchar(20) DEFAULT 'in-app',
  PRIMARY KEY (`idtiposavisos`),
  UNIQUE KEY `tiposavisoscodigo_UNIQUE` (`tiposavisoscodigo`)
) ENGINE=InnoDB AUTO_INCREMENT=7 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;


DROP TABLE IF EXISTS `usuarios`;
CREATE TABLE `usuarios` (
  `idusuarios` int(11) NOT NULL AUTO_INCREMENT,
  `usuariosnombre` varchar(100) NOT NULL,
